function esc(value: string): string {
  return value.replace(/[&<>]/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;" }[ch]!));
}

function list(items: string[]): string {
  return `<ul>${items.map((item) => `<li>${esc(item)}</li>`).join("")}</ul>`;
}

function layout(title: string, description: string, body: string): string {
  return `<!doctype html><html lang="en"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>${title}</title><meta name="description" content="${description}"/><link rel="canonical" href="${BASE_URL}/"/><meta name="theme-color" content="#08090a"/><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&family=JetBrains+Mono:wght@400;500&display=swap" rel="stylesheet"><style>${css()}</style></head><body><nav class="nav"><div class="wrap navin"><a class="brand" href="/"><span class="mark"></span><span>VeracityAPI</span></a><div class="links"><a href="/docs">Docs</a><a href="/how-it-works">How it works</a><a href="/use-cases">Use cases</a><a href="/evals">Evals</a><a href="/examples">Examples</a><a href="/pricing">Pricing</a><a href="/openapi.json">OpenAPI</a><a class="btn primary" href="/account">Account</a></div></div></nav><main class="wrap page">${body}</main><footer class="footer"><div class="wrap">VeracityAPI · Content trust and specificity scoring for agents — not proof of authorship or truth. <a href="/llms.txt">llms.txt</a> · <a href="/.well-known/agents.json">agents.json</a> · <a href="/sitemap.xml">sitemap</a></div></footer></body></html>`;
}

function css(): string { return `:root{color-scheme:dark;--bg:#08090a;--panel:#0f1011;--text:#f7f8f8;--muted:#a2a8b3;--line:rgba(255,255,255,.08);--accent:#7170ff;--good:#10b981;--warn:#f59e0b;--bad:#ef4444;--mono:'JetBrains Mono',ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;--sans:'Inter',system-ui,-apple-system,Segoe UI,Roboto,sans-serif}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 20% -10%,rgba(113,112,255,.18),transparent 34rem),var(--bg);color:var(--text);font-family:var(--sans)}a{color:inherit}.wrap{max-width:1120px;margin:0 auto;padding:0 22px}.nav{position:sticky;top:0;z-index:20;background:rgba(8,9,10,.78);backdrop-filter:blur(18px);border-bottom:1px solid var(--line)}.navin{height:68px;display:flex;align-items:center;justify-content:space-between}.brand{display:flex;gap:10px;align-items:center;text-decoration:none;font-weight:600}.mark{width:28px;height:28px;border:1px solid var(--line);border-radius:8px;background:linear-gradient(135deg,rgba(113,112,255,.9),rgba(56,189,248,.2))}.links{display:flex;gap:14px;align-items:center;color:#d0d6e0;font-size:13px}.links a{text-decoration:none}.btn{border:1px solid var(--line);background:rgba(255,255,255,.04);color:#fff;border-radius:8px;padding:10px 13px;text-decoration:none;font:500 13px var(--sans);cursor:pointer;display:inline-flex}.btn.primary{background:linear-gradient(135deg,#5e6ad2,#7170ff)}.page{padding:56px 22px 72px}.eyebrow{color:#d0d6e0;font:500 12px var(--mono);text-transform:uppercase;letter-spacing:.08em}h1{font-size:clamp(38px,6vw,64px);line-height:.98;letter-spacing:-.05em;margin:14px 0}h2{font-size:34px;letter-spacing:-.035em;margin:34px 0 12px}h3{margin:0 0 8px}.lead{max-width:850px;color:var(--muted);font-size:18px;line-height:1.65}.grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:16px;margin:28px 0}.triple{grid-template-columns:repeat(3,minmax(0,1fr))}.card{border:1px solid var(--line);background:linear-gradient(180deg,rgba(255,255,255,.045),rgba(255,255,255,.018));border-radius:16px;padding:20px;text-decoration:none}.card p,.card li{color:var(--muted);line-height:1.65}.label{font:500 12px var(--mono);color:#b8c0ff;text-transform:uppercase;letter-spacing:.08em}.stat{font-size:48px;letter-spacing:-.05em}.good{color:var(--good)}.warn{color:var(--warn)}.bad{color:var(--bad)}code{font-family:var(--mono);color:#dbeafe}pre{white-space:pre-wrap;background:#050607;border:1px solid var(--line);border-radius:12px;padding:16px;overflow:auto;color:#dbeafe;font:13px/1.55 var(--mono)}.table{width:100%;border-collapse:collapse;margin:20px 0}.table th,.table td{border-bottom:1px solid var(--line);padding:13px;text-align:left;color:#d0d6e0}.notice{display:none;border:1px solid rgba(16,185,129,.35);background:rgba(16,185,129,.08);padding:12px;border-radius:10px;margin-bottom:14px}.formgrid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}input,select,textarea{width:100%;margin-top:7px;border:1px solid var(--line);background:#090a0b;color:#fff;border-radius:10px;padding:12px;font:14px var(--sans)}textarea{min-height:150px}.footer{border-top:1px solid var(--line);padding:26px 0;color:var(--muted);font-size:13px}.pill{display:inline-flex;border:1px solid var(--line);border-radius:999px;padding:6px 9px;margin:4px;color:#d0d6e0;font:12px var(--mono)}@media(max-width:850px){.links{display:none}.grid,.triple,.formgrid{grid-template-columns:1fr}}`; }

export function useCasesIndexHtml(): string {
  return layout("VeracityAPI Use Cases for Agents", "Business-function use cases for agents evaluating VeracityAPI.", `<section class="hero"><div class="eyebrow">Agent use cases</div><h1>Business functions agents can protect with content trust scoring.</h1><p class="lead">These pages are written for agents evaluating whether VeracityAPI is worth calling in a workflow. Each use case explains the business value, trigger point, request context, policy mapping, automation recipe, evidence to inspect, KPIs, and caveats.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/openapi.json">OpenAPI</a> <a class="btn" href="/llms.txt">Agent instructions</a></p></section><section class="grid">${USE_CASES.map((u, i) => `<a class="card" href="/use-cases/${u.slug}"><div class="label">${String(i + 1).padStart(2, "0")} · ${esc(u.eyebrow)}</div><h3>${esc(u.title)}</h3><p>${esc(u.summary)}</p></a>`).join("")}</section>`);
}

export function useCaseHtml(slug: string): string | null {
  const u = USE_CASES.find((item) => item.slug === slug);
  if (!u) return null;
  const modality = u.modality ?? "text";
  const request = modality === "image"
    ? JSON.stringify({ image_url: u.sampleImageUrl ?? "https://example.com/image.jpg", context: u.context, privacy_mode: true }, null, 2)
    : JSON.stringify({ text: u.sampleText, context: u.context, privacy_mode: true }, null, 2);
  const requestBlock = modality === "image"
    ? `<section class="card"><h3>Request template</h3><pre>curl ${API_BASE_URL}/v1/analyze-image \\n  -H "Authorization: Bearer ***" \\n  -H "Content-Type: application/json" \\n  -d '${esc(request)}'</pre></section>`
    : modality === "audio_planned"
      ? `<section class="card"><h3>Agent workflow template</h3><p><b>Status:</b> no public VeracityAPI audio endpoint is shipped yet. This page is a discoverable workflow plan for agents; do not call a nonexistent audio route. When audio support ships, use this manifest shape and conservative policy.</p><pre>${esc(JSON.stringify({ audio_url: "https://your-secure-storage.example/clip.mp3", transcript: "optional caller-supplied transcript", context: u.context, privacy_mode: true }, null, 2))}</pre></section>`
      : `<section class="card"><h3>Request template</h3><pre>curl ${API_BASE_URL}/v1/analyze-text \\n  -H "Authorization: Bearer ***" \\n  -H "Content-Type: application/json" \\n  -d '${esc(request)}'</pre></section>`;
  const inputLabel = modality === "image" ? "What image URL to submit" : modality === "audio_planned" ? "What audio manifest to prepare" : "What text to submit";
  const costNotes = modality === "image"
    ? "Image analysis is a flat $0.02 per image. The endpoint accepts HTTPS image URLs, stores no image bytes, and logs only a URL hash plus hostname. Current v0.1 latency is vision-model-bound, so preflight balance and retry carefully."
    : modality === "audio_planned"
      ? "Audio pricing and latency are not published because no public audio endpoint is shipped yet. Treat these pages as workflow and discoverability preparation; use text/image APIs for live integrations today."
      : "Pricing is character-bucketed: ≤4k chars $0.01, ≤20k $0.03, ≤50k $0.06, ≤100k $0.12. Most short captions/emails cost $0.01; longer pages or chapters should be scored by section. Current v0.1 latency is LLM-bound, so batch/concurrent orchestration is recommended for high-volume pipelines.";
  const checklist = modality === "image"
    ? ["Does this workflow have a costly failure mode from manipulated or synthetic-looking visuals?", "Can the agent store evidence categories without storing raw image bytes or full URLs?", "Should this workflow fail open, fail closed, or queue human review if image scoring is unavailable?", "Which field drives policy: recommended_action, risk_level, content_trust_score, or synthetic_image_risk?", "What local provenance check should complement the API score?"]
    : modality === "audio_planned"
      ? ["Is the page clearly marked as a planned workflow, not a shipped endpoint?", "What consent, retention, and privacy rules govern the audio clips?", "What independent verification is required before consequential decisions?", "How will the agent behave while audio scoring is unavailable?", "Which reviewer outcome should be captured for future calibration?"]
      : ["Does this workflow have a costly failure mode from generic or weak-provenance text?", "Can the agent map evidence spans back to editable source locations?", "Should this workflow fail open, fail closed, or queue human review if VeracityAPI is unavailable?", "Which field drives policy: recommended_action, risk_level, content_trust_score, specificity_risk, or provenance_weakness?", "What local rule should complement the API score?"];
  const policyCode = `if (result.recommended_action === "allow") continueWorkflow();\nif (result.recommended_action === "revise") rewriteWith(result.evidence, result.recommended_fixes);\nif (result.recommended_action === "human_review") queueForHumanReview(result);\nif (result.recommended_action === "reject") discardOrRebuild();`;
  return layout(`${u.title} | VeracityAPI use case`, u.summary, `<section class="hero"><div class="eyebrow">${esc(u.eyebrow)}</div><h1>${esc(u.title)}</h1><p class="lead">${esc(u.summary)}</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">All use cases</a> <a class="btn" href="/docs">Docs</a></p></section>
<section class="grid"><div class="card"><h3>Business value</h3>${list(u.businessValue)}</div><div class="card"><h3>Agent job to be done</h3><p>${esc(u.agentJob)}</p><p><span class="pill">format: ${esc(u.context.format)}</span><span class="pill">intended_use: ${esc(u.context.intended_use)}</span><span class="pill">domain: ${esc(u.context.domain)}</span></p></div></section>
<section class="grid"><div class="card"><h3>When to call VeracityAPI</h3><p>${esc(u.trigger)}</p><h3>${inputLabel}</h3><p>${esc(u.input)}</p></div><div class="card"><h3>Decision policy</h3>${list(u.policy)}</div></section>
${requestBlock}
<section class="grid"><div class="card"><h3>Automation recipe</h3>${list(u.automation)}</div><div class="card"><h3>Evidence spans agents should inspect</h3>${list(u.evidence)}</div></section>
<section class="grid"><div class="card"><h3>Policy pseudocode</h3><pre>${policyCode}</pre></div><div class="card"><h3>KPIs to track</h3>${list(u.kpis)}</div></section>
<section class="grid"><div class="card"><h3>What can go wrong</h3>${list(u.caveats)}</div><div class="card"><h3>Cost and latency notes</h3><p>${costNotes}</p></div></section>
<section class="card"><h3>Agent evaluation checklist</h3><ul>${checklist.map((item) => `<li>${esc(item)}</li>`).join("")}</ul></section>`);
}

export function docsHtml(): string { return layout("VeracityAPI Docs", "API docs for VeracityAPI content trust scoring.", `<section class="hero"><div class="eyebrow">Developer docs</div><h1>Integrate a content trust gate in one API call.</h1><p class="lead">Call VeracityAPI before an agent publishes, cites, trains on, or moderates text or images. The text API scores specificity gaps, generic slop, weak evidence, and synthetic-looking texture; the image API scores visible synthetic-image artifacts. Both return evidence and a recommended workflow action.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">Agent use cases</a> <a class="btn" href="/how-it-works">How it works</a> <a class="btn" href="/openapi.json">OpenAPI JSON</a> <a class="btn" href="/llms.txt">llms.txt</a></p></section>
<section class="grid"><div class="card"><div class="label">Text endpoint</div><pre>POST ${API_BASE_URL}/v1/analyze-text</pre><p>Auth: bearer token in the Authorization header. Raw text is not stored when privacy_mode is true, which is the default.</p></div><div class="card"><div class="label">Batch endpoint</div><pre>POST ${API_BASE_URL}/v1/analyze-batch</pre><p>Synchronous batch scoring for 1-25 text items. Each item is capped at 4,000 chars, total batch text is capped at 50,000 chars, and billing is the sum of per-item text prices.</p></div><div class="card"><div class="label">Balance endpoint</div><pre>GET ${API_BASE_URL}/v1/balance</pre><p>Returns account balance, last usage timestamp, and recent usage windows so agents can preflight autonomous runs.</p></div><div class="card"><div class="label">Image endpoint</div><pre>POST ${API_BASE_URL}/v1/analyze-image</pre><p>Submit an https image_url. VeracityAPI stores no image bytes, logs only a URL hash plus hostname, and charges $0.02/image.</p></div><div class="card"><div class="label">Not an AI detector</div><p>VeracityAPI does not prove whether a human or model made content. It tells agents whether text or images are safe enough for the requested workflow.</p></div></section>
<section class="card"><h3>Current thresholds and action policy</h3><p>v0.1 risk_level uses <code>max(synthetic_risk, slop_risk)</code>: below 0.40 = low, below 0.70 = medium, 0.70+ = high. recommended_action then depends on intended_use.</p><table class="table"><tr><th>intended_use</th><th>low</th><th>medium</th><th>high</th></tr><tr><td>publish</td><td>allow</td><td>revise</td><td>human_review</td></tr><tr><td>train</td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td>cite</td><td>allow</td><td>human_review</td><td>reject</td></tr><tr><td>moderate</td><td>allow</td><td>allow</td><td>revise</td></tr><tr><td>other</td><td>allow</td><td>revise</td><td>human_review</td></tr></table></section>
<section class="grid"><div class="card"><h3>TypeScript text fetch</h3><pre>const res = await fetch("${API_BASE_URL}/v1/analyze-text", {\n  method: "POST",\n  headers: {\n    "Authorization": "Bearer $VERACITYAPI_KEY",\n    "Content-Type": "application/json"\n  },\n  body: JSON.stringify({\n    text,\n    context: { format: "article", intended_use: "publish", domain: "travel safety" },\n    privacy_mode: true\n  })\n});\nconst risk = await res.json();</pre></div><div class="card"><h3>Image curl</h3><pre>curl ${API_BASE_URL}/v1/analyze-image \\n  -H "Authorization: Bearer $VERACITYAPI_KEY" \\n  -H "Content-Type: application/json" \\n  -d '{"image_url":"https://veracityapi.com/demo/influencer-beauty-tonic.jpg","context":{"format":"social_post","intended_use":"publish","domain":"influencer product post"},"privacy_mode":true}'</pre></div><div class="card"><h3>Python requests</h3><pre>import os, requests\n\nr = requests.post("${API_BASE_URL}/v1/analyze-text",\n  headers={"Authorization": f"Bearer {os.environ['VERACITYAPI_KEY']}"},\n  json={"text": text, "context": {"format": "article", "intended_use": "publish"}, "privacy_mode": True})\nprint(r.json())</pre></div></section>`); }

export function howItWorksHtml(): string { return layout("How VeracityAPI Works", "Transparent model, scoring, thresholds, and limitations for VeracityAPI.", `<section class="hero"><div class="eyebrow">Transparency</div><h1>Not authorship proof. A specificity and trust gate for agents.</h1><p class="lead">Binary AI detection is brittle. VeracityAPI is built for the more useful workflow question: should this text or image be allowed, revised, reviewed, or rejected before an agent uses it?</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">Use cases</a> <a class="btn" href="/docs">Read docs</a> <a class="btn" href="/evals">Evals</a></p></section>
<section class="grid"><div class="card"><h3>What model is doing the scoring?</h3><p>v0.1 uses a structured LLM scoring pass via Anthropic Haiku, temperature 0, with schema-constrained tool output and deterministic post-processing. It is not a fine-tuned classifier yet.</p></div><div class="card"><h3>What does it measure?</h3><p>Observable signals: specificity gaps, generic phrasing, unsupported or weakly sourced claims, low-value/slop patterns, and synthetic-looking texture. The useful target is workflow risk, not ground-truth authorship.</p></div><div class="card"><h3>What changed after early audit?</h3><p>Public positioning now says content trust/specificity scoring, not AI-content detection. Responses include additive derived fields: content_trust_score, specificity_risk, provenance_weakness, and synthetic_texture_risk.</p></div><div class="card"><h3>What should agents do with it?</h3><p>Use it as a quality gate. Good output: allow. Generic but fixable output: revise. High-risk source/citation/training input: human_review or reject depending on intended_use.</p></div></section>
<section class="card"><h3>Current threshold matrix</h3><pre>risk_level = max(synthetic_risk, slop_risk)\n\n< 0.40  -> low\n< 0.70  -> medium\n>= 0.70 -> high\n\npublish:  low allow, medium revise, high human_review\ntrain:    low allow, medium human_review, high reject\ncite:     low allow, medium human_review, high reject\nmoderate: low allow, medium allow, high revise\nother:    low allow, medium revise, high human_review</pre></section>
<section class="card"><h3>Image scoring v0.1</h3><p><code>POST /v1/analyze-image</code> accepts an https <code>image_url</code>, calls a vision LLM with a constrained visible-artifact rubric, and returns <code>synthetic_image_risk</code>, <code>synthetic_risk</code> alias, evidence, fixes, trust score, risk level, and recommended action. VeracityAPI stores no image bytes and logs only a URL hash plus hostname. C2PA/EXIF/provenance verification is roadmap, not claimed in v0.1.</p></section>
<section class="grid"><div class="card"><h3>Known limitations</h3><ul><li>Does not prove whether text was written by AI or a human.</li><li>Good AI-assisted writing with concrete details may pass.</li><li>Weak human writing may be flagged — intentionally, if it is generic or unsupported.</li><li>English-calibrated first; non-English scoring is experimental until evals exist.</li><li>Latency is LLM-bound; use /v1/analyze-batch for pipeline batches and /v1/balance for preflight spend checks.</li></ul></div><div class="card"><h3>Near-term roadmap</h3><ul><li>Publish a labeled calibration set with false-positive slices.</li><li>Add configurable risk tolerance: lenient, standard, strict.</li><li>Add a fast heuristic prefilter before the full evidence pass.</li><li>Add async batch/webhooks after synchronous batch usage is proven.</li></ul></div></section>`); }

export function evalsHtml(): string { return layout("VeracityAPI Evals", "Early calibration and dogfooding evidence for VeracityAPI.", `<section class="hero"><div class="eyebrow">Early calibration</div><h1>Dogfooded on real travel-safety pages — not yet a benchmark.</h1><p class="lead">These are early calibration examples, not accuracy claims. Next step is a labeled eval set that reports false positives on good human writing, false negatives on polished AI, and action-agreement with editorial policy.</p></section><section class="grid triple"><div class="card"><div class="label">Tabiji Japan scam city pages</div><div class="stat">16</div><p>Pages analyzed through the production API with privacy_mode=true.</p></div><div class="card"><div class="label">Low risk / allow</div><div class="stat good">14</div><p>Concrete location-specific scam pages generally passed.</p></div><div class="card"><div class="label">High risk / human_review</div><div class="stat warn">2</div><p>Flagged pages are useful edge cases for calibration.</p></div></section><table class="table"><tr><th>Example</th><th>Result</th><th>Why it matters</th></tr><tr><td>Generic travel warning</td><td><span class="bad">high / human_review</span></td><td>Flags broad claims like “pickpockets are everywhere” with evidence spans and revision advice.</td></tr><tr><td>Specific Shinjuku ticket scam report</td><td><span class="good">low / allow</span></td><td>Concrete place, behavior, and verification details reduce specificity/slop risk.</td></tr><tr><td>Kyoto city page</td><td><span class="warn">high / human_review</span></td><td>Useful false-positive/edge-case candidate for calibration expansion.</td></tr></table><section class="card"><h3>Next eval target</h3><p>Build 200–500 labeled samples across good human firsthand writing, dry factual human writing, generic AI slop, polished AI with specifics, low-quality human SEO slop, and travel-safety examples. Report false-positive and false-negative slices by threshold.</p></section>`); }

export function examplesHtml(): string { return layout("VeracityAPI Examples", "Use cases and integration patterns for VeracityAPI.", `<section class="hero"><div class="eyebrow">Examples</div><h1>Start with business-function use cases.</h1><p class="lead">The full use-case library gives agents the trigger point, request context, policy mapping, automation recipe, KPIs, and caveats for real business workflows.</p><p><a class="btn primary" href="/use-cases">Open use case library</a> <a class="btn" href="/docs">Docs</a></p></section><section class="grid">${USE_CASES.slice(0, 6).map((u) => `<a class="card" href="/use-cases/${u.slug}"><h3>${esc(u.title)}</h3><p>${esc(u.summary)}</p></a>`).join("")}</section><section class="card"><h3>LangGraph-style tool wrapper</h3><pre>async function scoreContentTrust({ text, intendedUse = "publish" }) {\n  const r = await fetch("${API_BASE_URL}/v1/analyze-text", {\n    method: "POST",\n    headers: { "Authorization": "Bearer $VERACITYAPI_KEY", "Content-Type": "application/json" },\n    body: JSON.stringify({ text, context: { format: "article", intended_use: intendedUse }, privacy_mode: true })\n  });\n  return await r.json();\n}</pre></section>`); }

export function privacyHtml(): string { return layout("VeracityAPI Privacy", "Privacy and data retention notes for VeracityAPI.", `<section class="hero"><div class="eyebrow">Privacy</div><h1>Raw text and image bytes are off by default.</h1><p class="lead">VeracityAPI is built for content trust workflows where users may submit sensitive drafts, source text, or image URLs. The default request mode avoids storing raw text, and image analysis never stores raw image bytes.</p></section><section class="grid"><div class="card"><h3>Text privacy_mode=true</h3><p>Default. The API logs request metadata, a text hash, context JSON, response JSON, latency, and model version. Raw submitted text is stored as null.</p></div><div class="card"><h3>Image privacy</h3><p><code>/v1/analyze-image</code> accepts an https image URL, charges $0.02/image, and logs only a hash of the full URL plus the hostname. VeracityAPI does not persist full image URLs or image bytes.</p></div><div class="card"><h3>privacy_mode=false</h3><p>Reserved for explicit client opt-in when raw text retention is useful for debugging/evals. Image bytes are still not stored.</p></div><div class="card"><h3>Public demo</h3><p>The no-key text demo forces privacy_mode=true server-side, caps text at 4,000 chars, and has basic rate limiting. The image demo also forces privacy mode and rate limits by IP/cookie.</p></div><div class="card"><h3>Limitations</h3><p>Beta service. No regulated-data guarantees yet. Scores are probabilistic risk signals, not authorship proof or truth verification. Image v0.1 does not inspect EXIF or C2PA provenance metadata.</p></div></section>`); }

export function requestAccessHtml(): string { return layout("Request VeracityAPI Access", "Request a VeracityAPI private beta key.", `<section class="hero"><div class="eyebrow">Legacy request form</div><h1>Prefer self-serve account setup.</h1><p class="lead">VeracityAPI now supports email login, prepaid credits, and API key management at /account. Use this request form only for custom volume or partnership requests.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/pricing">View pricing</a></p></section><section class="card"><div id="notice" class="notice">Request received. We’ll follow up with details.</div><form id="access"><div class="formgrid"><label>Name<input name="name" required maxlength="120"/></label><label>Email<input type="email" name="email" required maxlength="180"/></label></div><div class="formgrid"><label>Company / project<input name="company" maxlength="160"/></label><label>Expected monthly volume<select name="volume"><option>under 1k</option><option>1k-10k</option><option>10k-100k</option><option>100k+</option></select></label></div><label>Agent use case<textarea name="use_case" required maxlength="1200" placeholder="e.g. pre-publish QA, RAG source triage, review moderation..."></textarea></label><p><button class="btn primary" type="submit">Submit request</button></p></form></section><script>const form=document.getElementById('access'),notice=document.getElementById('notice');form.onsubmit=async(e)=>{e.preventDefault();const data=Object.fromEntries(new FormData(form).entries());const r=await fetch('/request-access',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify(data)});if(r.ok){form.reset();notice.style.display='block'}else{const j=await r.json().catch(()=>({message:'Request failed'}));alert(j.message||j.error||'Request failed')}};</script>`); }

export function pricingHtml(): string { return layout("VeracityAPI Pricing", "Credit-based VeracityAPI pricing for API and agent usage.", `<section class="hero"><div class="eyebrow">Pricing</div><h1>New accounts get $1.50 free credit — enough for 150 short text analyses. No subscriptions. Buy credits when you need more. Every request debits your balance.</h1><p class="lead">VeracityAPI is priced for API-first and agent-first workflows: start with $1.50 free credit — enough for 150 short text analyses, call the API, and pay a fixed amount based on request size after that.</p><p><a class="btn primary" href="/account">Get API key</a> <a class="btn" href="/use-cases">Use cases</a> <a class="btn" href="/docs">Read docs</a> <a class="btn" href="/openapi.json">OpenAPI JSON</a></p></section><section class="card"><h3>Canonical analysis pricing</h3><table class="table"><tr><th>Request size</th><th>Price</th><th>Billing rule</th></tr><tr><td>≤4k characters</td><td><b>$0.01</b></td><td>Debited from prepaid balance per analysis</td></tr><tr><td>≤20k characters</td><td><b>$0.03</b></td><td>Debited from prepaid balance per analysis</td></tr><tr><td>≤50k characters</td><td><b>$0.06</b></td><td>Debited from prepaid balance per analysis</td></tr><tr><td>≤100k characters</td><td><b>$0.12</b></td><td>Debited from prepaid balance per analysis</td></tr><tr><td>&gt;100k characters</td><td>Chunk or contact us</td><td>Use multiple calls or request custom access</td></tr><tr><td>Synchronous text batch</td><td>Sum of item prices</td><td>1-25 items; ≤4k chars/item; ≤50k chars total</td></tr><tr><td>Image URL analysis</td><td><b>$0.02</b></td><td>Flat debit per image analysis; vision calls cost more than text</td></tr></table></section><section class="grid"><div class="card"><h3>How credits work</h3><p>Users load a VeracityAPI balance. Each authenticated text request is measured by input characters and assigned to a pricing bucket. Batch text requests are billed as the sum of per-item prices. Image analysis is a flat $0.02/image debit from the same balance. Agents can call GET /v1/balance before a run to check remaining credits and recent usage.</p></div><div class="card"><h3>Public demo</h3><p>The website demos remain free, no-key, privacy_mode=true, and rate limited. Text demo input is capped at 4,000 characters; image demo accepts an HTTPS image URL and logs no image bytes or full URL. New accounts also get $1.50 in API credits for authenticated workflow testing.</p></div></section>`); }
